&lt;p style=&quot;&quot;&gt;The correct answer is &lt;span style=&quot;font-weight: 700;&quot;&gt;&lt;u&gt;Tennis&lt;/u&gt;&lt;/span&gt;.&lt;/p&gt;

&lt;p style=&quot;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul style=&quot;&quot;&gt;
	&lt;li style=&quot;&quot;&gt;Davis Cup is associated with ​&lt;span style=&quot;font-weight: 700;&quot;&gt;&lt;u&gt;Lawn Tennis&lt;/u&gt;&lt;/span&gt;.&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;The Davis Cup was named after American collegian Dwight Filley Davis, who came up with the idea to start a challenging tennis match between the USA and Great Britain&lt;/span&gt;.&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;First played in 1900,&lt;/span&gt; it was originally called the International &lt;u&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Lawn Tennis Trophy&lt;/span&gt;&lt;/u&gt;.&lt;/li&gt;
	&lt;li&gt;The &lt;span style=&quot;font-weight: 700;&quot;&gt;Davis Cup&lt;/span&gt; is the premier international team event in men&amp;#39;s tennis.
	&lt;ul&gt;
		&lt;li&gt;It is run by the &lt;span style=&quot;font-weight: 700;&quot;&gt;International Tennis Federation&lt;/span&gt; and Kosmos Holding and is contested annually between teams from competing countries in a knock-out format.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p style=&quot;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/important-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Important Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt; &lt;/span&gt;&lt;/p&gt;

&lt;ul style=&quot;&quot;&gt;
	&lt;li&gt;The first &lt;span style=&quot;font-weight: 700;&quot;&gt;Davis Cup&lt;/span&gt; took place in 1900 and saw the USA take on Great Britain, then play under the name of the British Isles.

	&lt;ul&gt;
		&lt;li&gt;It was held at the&lt;span style=&quot;font-weight: 700;&quot;&gt; Longwood Cricket Club in Boston&lt;/span&gt; and the Americans surprised their opponents by racing into an unassailable 3-0 lead.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p style=&quot;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt; &lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;table border=&quot;1&quot; cellpadding=&quot;0&quot; cellspacing=&quot;0&quot; style=&quot;width:350px;&quot; width=&quot;690&quot;&gt;
	&lt;tbody&gt;
		&lt;tr&gt;
			&lt;td style=&quot;height: 12px;&quot;&gt;
			&lt;p&gt;&lt;strong&gt;SPORTS&lt;/strong&gt;&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;height: 12px;&quot;&gt;
