			&lt;p&gt;Ryder Cup (men), Solheim Cup (women), Walker Cup&lt;/p&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;height: 13px;&quot;&gt;
			&lt;p&gt;Archery&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;height: 13px;&quot;&gt;
			&lt;p&gt;Archery World Cup&lt;/p&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;height: 75px;&quot;&gt;
			&lt;p&gt;Lawn Tennis&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;height: 75px;&quot;&gt;
			&lt;p&gt;French open cup, US open cup, Australian open cup, Davis cup(men), Fed Cup (women), Wightman Cup (women)&lt;/p&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;height: 37px;&quot;&gt;
			&lt;p&gt;Table Tennis&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;height: 37px;&quot;&gt;
			&lt;p&gt;Travancore cup (women), Swaythling Cup (men), Bama Belleek cup&lt;/p&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
	&lt;/tbody&gt;
&lt;/table&gt;<br><br>&lt;p style=&quot;&quot;&gt;सही उत्तर &lt;span style=&quot;font-weight: 700;&quot;&gt;&lt;u&gt;टेनिस&lt;/u&gt;&lt;/span&gt; &lt;span style=&quot;&quot;&gt;है&lt;/span&gt;।&lt;/p&gt;

&lt;p style=&quot;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt; &lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li style=&quot;&quot;&gt;डेविस कप &lt;u&gt;&lt;strong&gt;लॉन टेनिस&lt;/strong&gt;&lt;/u&gt; से &lt;span style=&quot;&quot;&gt;संबंधित &lt;/span&gt;है।&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;डेविस कप का नाम अमेरिकी कॉलेजियन ड्वाइट फिली डेविस के नाम पर रखा गया था, जो संयुक्त राष्ट्र अमेरिका और ग्रेट ब्रिटेन के बीच एक चैलेंज टेनिस मैच शुरू करने का विचार लेकर आए थे&lt;/span&gt;।&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;यह पहली बार 1900 में खेला गया था,&lt;/span&gt; इसे प्रारम्भतः अंतर्राष्ट्रीय &lt;u&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;लॉन टेनिस ट्रॉफी&lt;/span&gt;&lt;/u&gt; कहा जाता था।&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: bold;  &quot;&gt;डेविस कप &lt;/span&gt;टेनिस में पुरुष वर्ग के खिलाडियों के लिए प्रमुख अंतरराष्ट्रीय प्रतिस्पर्धा है।
	&lt;ul&gt;
		&lt;li&gt;यह &lt;span style=&quot;font-weight: 700;&quot;&gt;अंतर्राष्ट्रीय टेनिस महासंघ&lt;/span&gt; और कॉसमॉस होल्डिंग द्वारा चलाया जाता है और प्रतिस्पर्धी देशों की टीमों के बीच नॉक-आउट प्रारूप में प्रतिवर्ष खेला जाता है।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p style=&quot;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/important-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Important Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt; &lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul style=&quot;&quot;&gt;
	&lt;li&gt;पहला &lt;span style=&quot;font-weight: 700;&quot;&gt;डेविस कप&lt;/span&gt; 1900 में हुआ और संयुक्त राज्य अमेरिका ने ग्रेट ब्रिटेन पर जीत हासिल की थी जिसे ब्रिटिश आइल्स के अधीन खेला गया था।

	&lt;ul&gt;
		&lt;li&gt;यह बोस्टन में लॉन्ग वुड क्रिकेट क्लब​&lt;span style=&quot;font-weight: 700;&quot;&gt; में&lt;/span&gt; आयोजित किया गया था जिसमें अमेरिकियों ने विरोधी टीम को 3-0 से हराकर इतिहास रच दिया था।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p style=&quot;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt; &lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;table border=&quot;1&quot; cellpadding=&quot;0&quot; cellspacing=&quot;0&quot; style=&quot;width:350px;&quot; width=&quot;690&quot;&gt;
	&lt;tbody&gt;
		&lt;tr&gt;
			&lt;td style=&quot;height: 12px;&quot;&gt;
			&lt;p&gt;&lt;strong&gt;खेल&lt;/strong&gt;&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;height: 12px;&quot;&gt;
			&lt;p&gt;&lt;strong&gt;कप और ट्रॉफी&lt;/strong&gt;&lt;/p&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;height: 25px;&quot;&gt;
			&lt;p&gt;क्रिकेट&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;height: 25px;&quot;&gt;
			&lt;p&gt;एशेज, रिलायंस कप, रोथमैन ट्रॉफी, सीके नायडू ट्रॉफी&lt;/p&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;height: 24px;&quot;&gt;
			&lt;p&gt;बास्केटबाल&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;height: 24px;&quot;&gt;
			&lt;p&gt;विलियम्स कप, बैंगलोर ब्लूज़ चैलेंज कप&lt;/p&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;height: 24px;&quot;&gt;
			&lt;p&gt;बैडमिंटन&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;height: 24px;&quot;&gt;
			&lt;p&gt;थॉमस कप, अग्रवाल कप, चड्ढा कप, दीवान कप&lt;/p&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;height: 25px;&quot;&gt;
			&lt;p&gt;फ़ुटबॉल&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;height: 25px;&quot;&gt;
			&lt;p&gt;कोलंबो कप, मर्डेका कप, डूरंड कप&lt;/p&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;height: 37px;&quot;&gt;
			&lt;p&gt;वालीबाल&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;height: 37px;&quot;&gt;
			&lt;p&gt;सेंटेनियल कप, फेडरेशन कप, इंदिरा प्रधान ट्रॉफी, शिवंती गोल्ड कप&lt;/p&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;height: 12px;&quot;&gt;
			&lt;p&gt;गोल्फ़&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;height: 12px;&quot;&gt;
			&lt;p&gt;राइडर कप (पुरुष), सोलहिम कप (महिला), वॉकर कप&lt;/p&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;height: 13px;&quot;&gt;
			&lt;p&gt;तीरंदाजी&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;height: 13px;&quot;&gt;
			&lt;p&gt;तीरंदाजी विश्व कप&lt;/p&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;height: 75px;&quot;&gt;
			&lt;p&gt;लान टेनिस&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;height: 75px;&quot;&gt;
			&lt;p&gt;फ्रेंच ओपन कप, यूएस ओपन कप, ऑस्ट्रेलियन ओपन कप, &lt;span style=&quot;&quot;&gt;डेविस कप&lt;/span&gt; (पुरुष), फेड कप (महिला), वाइटमैन कप (महिला)&lt;/p&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;height: 37px;&quot;&gt;
			&lt;p&gt;टेबल टेनिस&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;height: 37px;&quot;&gt;
			&lt;p&gt;त्रावणकोर कप (महिला), स्वेथलिंग कप (पुरुष), बामा बेलेक कप&lt;/p&gt;
			&lt;/td&gt;
