			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;strong&gt;Terminology&lt;/strong&gt;&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;span style=&quot;&quot;&gt;Badminton&lt;/span&gt;&lt;/td&gt;
