			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;span style=&quot; line-height: 107%; &quot;&gt;Service, Grandslam, Advantage,&amp;nbsp;Deuce, Game Point, Breakpoint; Smash,&amp;nbsp;Shot, Grass Court. Break, Drop shot,&amp;nbsp;Netplay, Baseline, etc&lt;/span&gt;&lt;/td&gt;
