&lt;/table&gt;<br><br>&lt;p&gt;सही उत्&amp;zwj;तर &lt;u&gt;&lt;strong&gt;फुटबॉल&lt;/strong&gt;&lt;/u&gt;&lt;span style=&quot;&quot;&gt;&lt;strong&gt;&amp;nbsp;&lt;/strong&gt;है&lt;/span&gt;।&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;u&gt;&lt;strong&gt;फुटबॉल में &amp;quot;ऑफसाइड ट्रैप&amp;quot; शब्द का प्रयोग किया जाता है।&lt;/strong&gt;&lt;/u&gt;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;फ़ुटबॉल &lt;/strong&gt;से जुड़ी शब्दावलियाँ&amp;nbsp;हैं, जिसके अंतर्गत बनाना किक, हेड, पेनल्टी किक, ड्रिबल, ऑफसाइड, हैट्रिक, फाउल, लेफ्ट आउट, गोल, राइट आउट, स्टॉपर, डिफेंडर, मूव, पास, कॉमर बैक, बेसलाइन, रिबाउंड, ऑफसाइड ट्रैप आदि।&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;ऑफसाइड ट्रैप&amp;nbsp;&lt;/strong&gt;एक रणनीति&amp;nbsp;है जिसमें बचाव दल के खिलाड़ी एक या एक से अधिक विरोधी खिलाड़ियों को ऑफसाइड स्थिति में रखने के लिए ऊपर की ओर धक्का देते हैं।&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;फुटबॉल&lt;/strong&gt;:
	&lt;ul&gt;
		&lt;li&gt;विश्व के&amp;nbsp;पहले फुटबॉल क्लब &amp;#39;&lt;strong&gt;शेफील्ड फुटबॉल क्लब&lt;/strong&gt;&amp;#39; की स्थापना वर्ष 1857 में इंग्लैंड में हुई थी।&lt;/li&gt;
		&lt;li&gt;भारत का&amp;nbsp;पहला फुटबॉल क्लब &amp;#39;&lt;strong&gt;डलहौजी क्लब&lt;/strong&gt;&amp;#39; था।&lt;/li&gt;
		&lt;li&gt;फुटबॉल की शीर्ष संस्था &lt;strong&gt;&amp;#39;फेडरेशन ऑफ इंटरनेशनल फुटबॉल एसोसिएशन&amp;#39;&lt;/strong&gt; (फीफा) है, जिसका गठन &lt;strong&gt;21 मई, 1904&lt;/strong&gt; को किया गया था।&lt;/li&gt;
		&lt;li&gt;फीफा का &lt;strong&gt;मुख्यालय ज्यूरिख &lt;/strong&gt;में है और यह स्विट्जरलैंड के कानून के अंतर्गत स्थापित एक संघ है।&lt;/li&gt;
		&lt;li&gt;&lt;strong&gt;1908 &lt;/strong&gt;में आधिकारिक तौर पर ओलंपिक खेलों में फुटबॉल को प्रतिस्पर्धी खेल के रूप में शामिल किया गया था।&lt;/li&gt;
		&lt;li&gt;भारत ने वर्ष&amp;nbsp;&lt;strong&gt;1948&lt;/strong&gt; में &lt;strong&gt;लंदन &lt;/strong&gt;में आयोजित&amp;nbsp;विश्व &lt;strong&gt;ओलंपिक फुटबॉल प्रतियोगिता &lt;/strong&gt;में भाग लिया।&lt;/li&gt;
		&lt;li&gt;&lt;strong&gt;पहला विश्व कप 1930 &lt;/strong&gt;में &lt;strong&gt;उरुग्वे&lt;/strong&gt; में आयोजित किया गया था।&lt;/li&gt;
		&lt;li&gt;भारत में, भारतीय फुटबॉल संघ (IFA) &lt;strong&gt;राष्ट्रीय फुटबॉल चैम्पियनशिप&lt;/strong&gt; का आयोजन करता है।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

