			&lt;td&gt;&lt;span style=&quot;&quot;&gt;&lt;font color=&quot;#58595b&quot;&gt;बैडमिंटन&lt;/font&gt;&lt;/span&gt;&lt;/td&gt;
			&lt;td&gt;&lt;span style=&quot;&quot;&gt;&lt;font color=&quot;#58595b&quot;&gt;बेसलाइन, कैरी, सर्विस कोर्ट, फोर हैंड, बैक हैंड, स्मैश, हिट, ड्रॉप, नेट, लव, डबल फॉल्ट, आदि।&lt;/font&gt;&lt;/span&gt;&lt;/td&gt;
		&lt;/tr&gt;
