&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul style=&quot;&quot;&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Sachin Tendulkar&lt;/span&gt;:

	&lt;ul&gt;
		&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;quot;Playing It My Way&amp;quot; is the autobiography of former Indian cricketer&amp;nbsp;Sachin&amp;nbsp;Tendulkar.&amp;nbsp;&lt;/span&gt;

		&lt;ul&gt;
			&lt;li&gt;It was launched in Mumbai on 5 November 2014.&lt;/li&gt;
			&lt;li&gt;&lt;span data-darkreader-inline-color=&quot;&quot; style=&quot;color: rgb(77, 81, 86); --darkreader-inline-color: #b5aea4;&quot;&gt;The book was authored by Boria Majumdar&amp;nbsp;&lt;/span&gt;and Sachin Tendulkar.&lt;/li&gt;
		&lt;/ul&gt;
		&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Vinod Kambli&lt;/span&gt;:
	&lt;ul&gt;
		&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;quot;Vinod Kambli: The Lost Hero&amp;quot;&lt;/span&gt;&amp;nbsp;is a book on the biography of former Indian cricketer&amp;nbsp;Vinod Kambli.
		&lt;ul&gt;
			&lt;li&gt;The book was authored by Kunal Purandare.&lt;/li&gt;
		&lt;/ul&gt;
		&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Rahul Dravid&lt;/span&gt;:
	&lt;ul&gt;
		&lt;li&gt;&amp;quot;The Nice Guy Who Finished First&amp;quot; is a biography of Rahul Dravid.&lt;/li&gt;
		&lt;li&gt;The book was authored by Devendra Prabhudesai.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;<br><br>&lt;p&gt;सही उत्तर&lt;u&gt;&lt;strong&gt; &lt;span style=&quot;&quot;&gt;स्ट्रैट फ्रॉम द हार्ट है&lt;/span&gt;&lt;/strong&gt;&lt;/u&gt; &lt;span style=&quot;&quot;&gt;।&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&amp;nbsp;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul style=&quot;&quot;&gt;
	&lt;li&gt;कपिल देव अब तक 4 किताबें लिख चुके हैं:
	&lt;ul&gt;
		&lt;li&gt;बाय&amp;nbsp;गॉड्स डिक्री&amp;nbsp;(1985; आत्मकथा)&lt;/li&gt;
		&lt;li&gt;क्रिकेट माई स्टाइल (1987; आत्मकथा)&lt;/li&gt;
		&lt;li&gt;&lt;strong&gt;&lt;span style=&quot;&quot;&gt;स्ट्रैट फ्रॉम द हार्ट&lt;/span&gt;&lt;/strong&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt; (2004; आत्मकथा)&lt;/span&gt;&lt;/li&gt;
		&lt;li&gt;वी, द सिख (2019)&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&amp;nbsp;&lt;/span&gt;&lt;/p&gt;

&lt;ul style=&quot;&quot;&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;सचिन तेंदुलकर&lt;/span&gt; :

	&lt;ul&gt;
		&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;quot;प्लेइंग इट माई वे&amp;quot; पूर्व भारतीय क्रिकेटर सचिन तेंदुलकर की आत्मकथा है।&lt;/span&gt;

		&lt;ul&gt;
			&lt;li&gt;इसे 5 नवंबर 2014 को मुंबई में विमोचित&amp;nbsp;किया गया था।&lt;/li&gt;
			&lt;li&gt;&lt;span data-darkreader-inline-color=&quot;&quot; style=&quot;color: rgb(77, 81, 86); --darkreader-inline-color: #b5aea4;&quot;&gt;इस पुस्तक&amp;nbsp;के लेखक बोरिया मजूमदार&lt;/span&gt; और सचिन तेंदुलकर हैं।&lt;/li&gt;
		&lt;/ul&gt;
		&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;विनोद कांबली&lt;/span&gt; :
	&lt;ul&gt;
		&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;quot;विनोद कांबली: द लॉस्ट हीरो&amp;quot;&lt;/span&gt; पूर्व भारतीय क्रिकेटर विनोद कांबली की जीवनी पर एक किताब है।
		&lt;ul&gt;
			&lt;li&gt;पुस्तक के लेखक कुणाल पुरंदरे हैं।&lt;/li&gt;
		&lt;/ul&gt;
		&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;राहुल द्रविड़&lt;/span&gt; :
	&lt;ul&gt;
		&lt;li&gt;&amp;quot;द नाइस गाइ हू फिनिश्ड फर्स्ट&amp;quot; राहुल द्रविड़ की जीवनी है।&lt;/li&gt;
		&lt;li&gt;इस पुस्तक के लेखक देवेंद्र प्रभुदेसाई हैं।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;The correct answer is&amp;nbsp;&lt;span style=&quot;&quot;&gt;&lt;u&gt;&lt;strong&gt;Basketball&lt;/strong&gt;&lt;/u&gt;.&lt;/span&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

