&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;Mary Kom:&lt;/strong&gt;

	&lt;ul&gt;
		&lt;li&gt;&lt;strong&gt;Mary Kom &lt;/strong&gt;was born in&lt;strong&gt; Kagathei village&lt;/strong&gt;, &lt;strong&gt;Churachandpur district &lt;/strong&gt;of rural &lt;strong&gt;Manipur&lt;/strong&gt; in &lt;strong&gt;India&lt;/strong&gt;.&lt;/li&gt;
		&lt;li&gt;&lt;strong&gt;Mary Kom&lt;/strong&gt; won a &lt;strong&gt;silver medal&lt;/strong&gt; at the &lt;strong&gt;2008 Asian Women&amp;#39;s Boxing Championship&lt;/strong&gt; in &lt;strong&gt;India&lt;/strong&gt; and a fourth successive &lt;strong&gt;gold medal&lt;/strong&gt; at the&lt;strong&gt; 2008 AIBA Women&amp;#39;s World Boxing Championships &lt;/strong&gt;in &lt;strong&gt;China.&lt;/strong&gt;&lt;/li&gt;
		&lt;li&gt;&lt;strong&gt;Mary Kom &lt;/strong&gt;also&amp;nbsp;won&amp;nbsp;a &lt;strong&gt;gold medal&lt;/strong&gt; at the &lt;strong&gt;2009 Asian Indoor Games&lt;/strong&gt; in &lt;strong&gt;Vietnam.&lt;/strong&gt;&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

