			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;span style=&quot;color: (33, 37, 41);&quot;&gt;Dhyan Chand&lt;/span&gt;&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;Goal&amp;nbsp;&lt;/td&gt;
		&lt;/tr&gt;
	&lt;/tbody&gt;
&lt;/table&gt;

&lt;p&gt;&amp;nbsp;&lt;/p&gt;<br><br>&lt;p&gt;सही उत्तर &lt;u&gt;&lt;strong&gt;कल्पना चावला&lt;/strong&gt;&lt;/u&gt; है।&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;u&gt;&lt;strong&gt;द एज ऑफ टाइम&lt;/strong&gt;&lt;/u&gt; भारत में जन्मी नासा अंतरिक्ष यात्री &lt;u&gt;&lt;strong&gt;कल्पना चावला की जीवनी है।&lt;/strong&gt;&lt;/u&gt;&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;यह पुस्तक उनके पति जीन-पियरे हैरिसन द्वारा लिखी गई है&lt;/strong&gt;, और &lt;strong&gt;इसमें भारत में उनके जन्म से लेकर अमेरिका में स्नातक की पढ़ाई तक के उनके जीवन का उल्लेख किया गया है&lt;/strong&gt;, जिसके बाद 1994 में नासा के अंतरिक्ष यात्री दल में उनके चयन के साथ एयरोस्पेस करियर का समापन हुआ।&lt;/li&gt;
	&lt;li&gt;इसमें उनके &lt;strong&gt;अंतरिक्ष यात्री प्रशिक्षण और दो अंतरिक्ष&lt;/strong&gt; शटल उड़ानों,&lt;strong&gt; 1997 में &lt;/strong&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;STS-87&lt;/span&gt; &lt;strong&gt;और 2003 में कष्टपूर्ण&lt;/strong&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;&amp;nbsp;STS-107&lt;/span&gt; का विवरण दिया गया है।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

